from dataclasses import dataclass

@dataclass
class MSPDimensionScore:
    dimension: str
    score: int          # 1–5
    weight: float       # Fraction summing to 1.0 across all dimensions
    notes: str = ""

    @property
    def weighted_score(self) -> float:
        return self.score * self.weight

@dataclass
class MSPQualificationResult:
    partner_name: str
    dimensions: list[MSPDimensionScore]
    disqualifying_gaps: list[str]

    @property
    def total_score(self) -> float:
        return sum(d.weighted_score for d in self.dimensions)

    @property
    def qualifies(self) -> bool:
        if self.disqualifying_gaps:
            return False
        # All dimensions must score >= 3; overall weighted score >= 3.0
        return all(d.score >= 3 for d in self.dimensions) and self.total_score >= 3.0

    def scorecard(self) -> str:
        lines = [f"MSP: {self.partner_name}", f"Total: {self.total_score:.2f}/5.00"]
        for d in self.dimensions:
            lines.append(f"  {d.dimension}: {d.score}/5 (weight {d.weight:.0%}) → {d.weighted_score:.2f}")
        if self.disqualifying_gaps:
            lines.append(f"DISQUALIFIED: {'; '.join(self.disqualifying_gaps)}")
        else:
            lines.append("QUALIFIED" if self.qualifies else "NOT QUALIFIED")
        return "\n".join(lines)

def evaluate_msp(partner_name: str, scores: dict[str, int], gaps: list[str]) -> MSPQualificationResult:
    weights = {
        "GenAI Technical Depth": 0.35,
        "Compliance & Security": 0.25,
        "Delivery Track Record": 0.20,
        "Commercial Stability": 0.10,
        "Vendor Relationships": 0.10,
    }
    dimensions = [
        MSPDimensionScore(dim, scores.get(dim, 1), weight)
        for dim, weight in weights.items()
    ]
    return MSPQualificationResult(partner_name, dimensions, gaps)

# Example evaluation
result = evaluate_msp(
    "Acme GenAI Partners",
    {
        "GenAI Technical Depth": 4,
        "Compliance & Security": 3,
        "Delivery Track Record": 4,
        "Commercial Stability": 3,
        "Vendor Relationships": 4,
    },
    gaps=[],
)
print(result.scorecard())
# MSP: Acme GenAI Partners
# Total: 3.70/5.00
# QUALIFIED
